<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin-top:10px;}
  button{background:#444;border:none;padding:6px 12px;margin:2px;color:#fff;border-radius:4px;cursor:pointer;}
  button:hover{background:#555;}
  button.active{background:#888;}
  canvas{border:1px solid #555;background:#111;}
</style>
</head>
<body>
<canvas id="sand" width="400" height="400"></canvas>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const wCells = 80, hCells = 80;
  const cellSize = canvas.width / wCells; // 5px
  const EMPTY=0,SAND=1,WATER=2,WALL=3,ACID=4;
  const materialNames=['empty','sand','water','wall','acid'];
  let grid = new Uint8Array(wCells*hCells);
  let buffer = new Uint8Array(grid.length); // for rendering
  let currentMat = SAND;

  // UI
  const buttons = {
    sand: document.getElementById('mat-sand'),
    water: document.getElementById('mat-water'),
    wall: document.getElementById('mat-wall'),
    acid: document.getElementById('mat-acid'),
    empty: document.getElementById('mat-empty')
  };
  Object.values(buttons).forEach(btn=>btn.addEventListener('click',e=>{
    currentMat = parseInt(e.target.id.split('-')[1])||SAND;
    setActiveButton();
  }));
  function setActiveButton(){
    Object.entries(buttons).forEach(([k,btn])=>{
      btn.classList.toggle('active', k===materialNames[currentMat]);
    });
  }
  setActiveButton();

  document.getElementById('clear').addEventListener('click',()=>{grid.fill(EMPTY);});

  // Painting
  let drawing=false;
  canvas.addEventListener('mousedown',e=>{drawing=true;paint(e);});
  canvas.addEventListener('mousemove',e=>{if(drawing) paint(e);});
  window.addEventListener('mouseup',()=>drawing=false);
  function paint(e){
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - rect.left)/cellSize);
    const y = Math.floor((e.clientY - rect.top)/cellSize);
    if(x>=0&&x<wCells&&y>=0&&y<hCells) set(x,y,currentMat);
  }

  // Simulation step
  function step(){
    for(let y=hCells-1;y>=0;--y){
      for(let x=0;x<wCells;++x){
        const idx = y*wCells+x;
        const cell = grid[idx];
        if(cell===EMPTY||cell===WALL) continue;
        switch(cell){
          case SAND: moveSand(x,y); break;
          case WATER: moveWater(x,y); break;
          case ACID: moveAcid(x,y); break;
        }
      }
    }
  }

  function moveSand(x,y){
    const below = getCell(x,y+1);
    if(below===EMPTY){ set(x,y,EMPTY); set(x,y+1,SAND); return;}
    if(below===WATER||below===ACID){ swapCells(x,y,x,y+1); return;}
    // try diagonals
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx=x+d, ny=y+1;
      if(nx>=0&&nx<wCells){
        const ncell=getCell(nx,ny);
        if(ncell===EMPTY){ set(x,y,EMPTY); set(nx,ny,SAND); return;}
      }
    }
  }

  function moveWater(x,y){
    const below = getCell(x,y+1);
    if(below===EMPTY){ set(x,y,EMPTY); set(x,y+1,WATER); return;}
    // spread horizontally
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx=x+d;
      if(nx>=0&&nx<wCells && getCell(nx,y)===EMPTY){
        set(x,y,EMPTY); set(nx,y,WATER); return;
      }
    }
  }

  function moveAcid(x,y){
    // dissolve neighbors
    const dirs=[-1,0,1];
    for(const d of dirs){
      if(d!==0){
        const nx=x+d, ny=y+1;
        if(nx>=0&&nx<wCells && ny<hCells){
          const ncell=getCell(nx,ny);
          if(ncell===SAND||ncell===WALL){ set(nx,ny,EMPTY); }
        }
      }
    }
    // move like water
    const below = getCell(x,y+1);
    if(below===EMPTY){ set(x,y,EMPTY); set(x,y+1,ACID); return;}
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx=x+d;
      if(nx>=0&&nx<wCells && getCell(nx,y)===EMPTY){
        set(x,y,EMPTY); set(nx,y,ACID); return;
      }
    }
  }

  function getCell(x,y){ return (y<0||y>=hCells||x<0||x>=wCells)?WALL:grid[y*wCells+x];}
  function set(x,y,val){ if(y>=0&&y<hCells&&x>=0&&x<wCells) grid[y*wCells+x]=val; }
  function swapCells(ax,ay,bx,by){
    const aIdx=ay*wCells+ax;
    const bIdx=by*wCells+bx;
    [grid[aIdx],grid[bIdx]]=[grid[bIdx],grid[aIdx]];
  }

  // Rendering
  function render(){
    buffer.set(grid);
    const imgData = ctx.createImageData(canvas.width, canvas.height);
    for(let i=0;i<buffer.length;i++){
      const col = buffer[i];
      const r,g,b,a=255;
      switch(col){
        case EMPTY: [r,g,b]=[0,0,0]; break;
        case SAND: [r,g,b]=[194,178,128]; break;
        case WATER:[r,g,b]=[64,164,223]; break;
        case WALL: [r,g,b]=[100,100,100]; break;
        case ACID: [r,g,b]=[0,255,0]; break;
      }
      const idx=i*4;
      imgData.data[idx]=r;imgData.data[idx+1]=g;imgData.data[idx+2]=b;imgData.data[idx+3]=a;
    }
    ctx.putImageData(imgData,0,0);
  }

  function loop(){
    step();
    render();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);

  // API
  window.sim = {
    w: wCells,
    h: hCells,
    tick(n){ for(let i=0;i<n;i++) step(); },
    get(x,y){ return materialNames[getCell(x,y)]; },
    set(x,y,m){ const id=materialNames.indexOf(m); if(id>=0)set(x,y,id); },
    clear(){ grid.fill(EMPTY); }
  };
})();
</script>
</body>
</html>
